#include <stdio.h>
#include <string.h>
int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        char S[100005];
        scanf("%s", S);
        int n = strlen(S);
        int pairs = 0;
        for (int i = 0; i < n - 1; ) {
            if (S[i] != S[i+1]) { pairs++; i += 2; }
            else i++;
        }
        printf("%d\n", pairs);
    }
    return 0;
}

